    "headHtml": "<script src=\"https://cdn.tailwindcss.com?plugins=forms,container-queries\"></script><link href=\"https://fonts.googleapis.com/css2?family=Manrope:wght@200..800&amp;family=Inter:wght@300..700&amp;family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&amp;display=swap\" rel=\"stylesheet\"><script id=\"tailwind-config\">\n        tailwind.config = {\n          darkMode: \"class\",\n          theme: {\n            extend: {\n              \"colors\": {\n                      \"primary\": \"#fe6b00\", /* Industrial Orange */\n                      \"on-primary\": \"#ffffff\",\n                      \"secondary\": \"#001736\", /* Deep Navy */\n                      \"on-secondary\": \"#ffffff\",\n                      \"background\": \"#ffffff\",\n                      \"on-background\": \"#191c1e\",\n                      \"surface\": \"#f8f9fb\",\n                      \"on-surface\": \"#191c1e\",\n                      \"surface-variant\": \"#e0e3e5\",\n                      \"on-surface-variant\": \"#43474f\",\n                      \"outline\": \"#747780\",\n                      \"outline-variant\": \"#c4c6d0\",\n                      \"inverse-surface\": \"#2d3133\",\n                      \"inverse-on-surface\": \"#eff1f3\",\n                      \"primary-container\": \"#ffdbcc\",\n                      \"on-primary-container\": \"#351000\",\n                      \"secondary-container\": \"#002b5c\",\n                      \"on-secondary-container\": \"#d6e3ff\"\n              },\n              \"borderRadius\": {\n                      \"DEFAULT\": \"0rem\",\n                      \"sm\": \"0rem\",\n                      \"md\": \"0rem\",\n                      \"lg\": \"0rem\",\n                      \"xl\": \"0rem\",\n                      \"full\": \"9999px\"\n              },\n              \"fontFamily\": {\n                      \"headline\": [\"Manrope\", \"sans-serif\"],\n                      \"body\": [\"Inter\", \"sans-serif\"],\n                      \"label\": [\"Inter\", \"sans-serif\"]\n              }\n            },\n          },\n        }\n    </script><style>\n        body { font-family: 'Inter', sans-serif; }\n        h1, h2, h3, h4, .font-headline { font-family: 'Manrope', sans-serif; }\n        .material-symbols-outlined {\n            font-variation-settings: 'FILL' 0, 'wght' 300, 'GRAD' 0, 'opsz' 24;\n        }\n        .kinetic-border {\n            position: relative;\n        }\n        .kinetic-border::after {\n            content: '';\n            position: absolute;\n            bottom: -8px;\n            left: 0;\n            width: 32px;\n            height: 2px;\n            background: theme('colors.primary');\n        }\n        .glass-effect {\n            background: rgba(255, 255, 255, 0.9);\n            backdrop-filter: blur(12px);\n        }\n    </style><link rel=\"stylesheet\" href=\"/assets/site-shell.css\"><script>window.__SITE_ROUTES__={\"home\": \"index.html\", \"products\": \"products/index.html\", \"products-agv-forklift\": \"products/agv-forklift.html\", \"products-lifting-agv\": \"products/lifting-agv.html\", \"products-storage-agv\": \"products/storage-agv.html\", \"products-agv-roller\": \"products/agv-roller.html\", \"products-composite-mobile-robot\": \"products/composite-mobile-robot.html\", \"solutions\": \"solutions/index.html\", \"solutions-asrs\": \"solutions/asrs.html\", \"solutions-material-handling\": \"solutions/material-handling.html\", \"solutions-picking\": \"solutions/picking.html\", \"solutions-software\": \"solutions/software.html\", \"case-studies\": \"case-studies/index.html\", \"case-studies-asrs\": \"case-studies/asrs.html\", \"case-studies-material-handling\": \"case-studies/material-handling.html\", \"case-studies-picking\": \"case-studies/picking.html\", \"case-studies-project-warehouse-upgrade\": \"case-studies/projects/automated-warehouse-upgrade.html\", \"about\": \"about/index.html\", \"contact\": \"contact/index.html\"};</script><script defer=\"\" src=\"/assets/site-shell.js\"></script><script type=\"module\" src=\"https://unpkg.com/@google/model-viewer/dist/model-viewer.min.js\"></script><script type=\"module\" src=\"/assets/home-hero-robot.js\"></script>",
